import React, { useState, useRef, useEffect } from 'react';
import axios from 'axios';
import {
  Send, Bot, User, HelpCircle, X, Maximize2, Minimize2,
  Calendar, DollarSign, BarChart3, Clock, BookOpen,
  Award, FileText, Users, Menu, Search, Loader
} from 'lucide-react';

const ChatbotInterface = () => {
  const [messages, setMessages] = useState([
    {
      id: 1,
      text: "Hello! I'm your ERP assistant. How can I help you today? 👋\n\nI can help you with:\n• Fees and payments\n• Attendance and results\n• Assignments and tasks\n• Upcoming events\n• Timetable and courses",
      sender: 'bot',
      timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
    }
  ]);
  
  const [inputText, setInputText] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isOpen, setIsOpen] = useState(false);
  const [isMinimized, setIsMinimized] = useState(false);
  const [quickActions, setQuickActions] = useState([]);
  const [studentInfo, setStudentInfo] = useState(null);
  const messagesEndRef = useRef(null);

  // Quick actions with realistic queries
  const defaultQuickActions = [
    { icon: <DollarSign size={16} />, label: 'Pending Fees', query: 'What is my pending fee?' },
    { icon: <BarChart3 size={16} />, label: 'Attendance', query: 'What is my attendance in Math?' },
   
  ];

  // Example queries
  const exampleQueries = [
    'What is my unpaid installment for semester 3?',
   
  ];

  useEffect(() => {
    setQuickActions(defaultQuickActions);
    loadStudentInfo();
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const loadStudentInfo = () => {
    // Try to get student info from various sources
    const userData = JSON.parse(localStorage.getItem('userInfo') || '{}');
    if (userData && userData.studentId) {
      setStudentInfo(userData);
    }
    
    // Also check session storage
    const sessionData = sessionStorage.getItem('studentId');
    if (sessionData && !studentInfo) {
      setStudentInfo({ studentId: sessionData });
    }
  };

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  const sendMessage = async (text = inputText) => {
    if (!text.trim() || isLoading) return;

    const userMessage = {
      id: messages.length + 1,
      text: text,
      sender: 'user',
      timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
    };

    setMessages(prev => [...prev, userMessage]);
    setInputText('');
    setIsLoading(true);

    try {
      // Get studentId from multiple sources
      const studentId = studentInfo?.studentId || 
                       localStorage.getItem('studentId') || 
                       sessionStorage.getItem('studentId') ||
                       'demo123';

      const response = await axios.post('http://localhost:65000/api/chatbot/chat', {
        query: text,
        studentId: studentId
      }, {
        headers: {
          'Content-Type': 'application/json'
        }
      });

      if (response.data.success) {
        const botMessage = {
          id: messages.length + 2,
          text: response.data.response,
          sender: 'bot',
          timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
          data: response.data.data,
          intent: response.data.intent,
          studentName: response.data.studentName,
          requiresFollowup: response.data.requiresFollowup
        };
        setMessages(prev => [...prev, botMessage]);
        
        // If student name returned, update info
        if (response.data.studentName && !studentInfo?.name) {
          setStudentInfo(prev => ({
            ...prev,
            name: response.data.studentName
          }));
        }
      } else {
        throw new Error(response.data.message);
      }
    } catch (error) {
      console.error('Chatbot error:', error);
      const errorMessage = {
        id: messages.length + 2,
        text: error.response?.data?.message || 
              "Sorry, I'm having trouble connecting. Please check your internet connection and try again.",
        sender: 'bot',
        timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
      };
      setMessages(prev => [...prev, errorMessage]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleQuickAction = (query) => {
    sendMessage(query);
  };

  const handleSuggestionClick = (suggestion) => {
    setInputText(suggestion);
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  };

  const clearChat = () => {
    setMessages([
      {
        id: 1,
        text: "Hello! I'm your ERP assistant. How can I help you today? 👋\n\nI can help you with:\n• Fees and payments\n• Attendance and results\n• Assignments and tasks\n• Upcoming events\n• Timetable and courses",
        sender: 'bot',
        timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
      }
    ]);
  };

  const formatMessage = (text) => {
    if (!text) return null;
    
    const lines = text.split('\n');
    return lines.map((line, lineIndex) => {
      // Process each line for formatting
      const parts = line.split(/(\*\*.*?\*\*|✅|⚠️|❌|💰|📊|📅|📈|📚|👤|🎉|🏠|📝|⏰|📍)/g);
      
      return (
        <div key={lineIndex} className="message-line">
          {parts.map((part, partIndex) => {
            if (part.startsWith('**') && part.endsWith('**')) {
              return <strong key={partIndex} className="message-bold">{part.slice(2, -2)}</strong>;
            }
            
            // Icons and emojis
            const iconMap = {
              '✅': '✅', '⚠️': '⚠️', '❌': '❌',
              '💰': '💰', '📊': '📊', '📅': '📅',
              '📈': '📈', '📚': '📚', '👤': '👤',
              '🎉': '🎉', '🏠': '🏠', '📝': '📝',
              '⏰': '⏰', '📍': '📍'
            };
            
            if (iconMap[part]) {
              return <span key={partIndex} className="message-icon">{part}</span>;
            }
            
            return part;
          })}
        </div>
      );
    });
  };

  return (
    <>
      {/* Chatbot Toggle Button */}
      {!isOpen && (
        <button 
          className="chatbot-toggle-btn"
          onClick={() => setIsOpen(true)}
          title="Open Chatbot"
        >
          <Bot size={24} />
          <span className="chatbot-pulse"></span>
        </button>
      )}

      {/* Chatbot Modal */}
      {isOpen && (
        <div className={`chatbot-modal ${isMinimized ? 'minimized' : ''}`}>
          {/* Header */}
          <div className="chatbot-header">
            <div className="chatbot-title">
              <Bot size={20} />
              <div>
                <h3>ERP Assistant</h3>
                <p className="chatbot-subtitle">
                  {studentInfo?.name ? `Hello, ${studentInfo.name}` : 'AI Student Support'}
                </p>
              </div>
            </div>
            <div className="chatbot-actions">
              <button 
                className="icon-btn"
                onClick={() => setIsMinimized(!isMinimized)}
                title={isMinimized ? "Maximize" : "Minimize"}
              >
                {isMinimized ? <Maximize2 size={18} /> : <Minimize2 size={18} />}
              </button>
              <button 
                className="icon-btn"
                onClick={clearChat}
                title="Clear chat"
              >
                <Menu size={18} />
              </button>
              <button 
                className="icon-btn close-btn"
                onClick={() => setIsOpen(false)}
                title="Close"
              >
                <X size={18} />
              </button>
            </div>
          </div>

          {!isMinimized && (
            <>
              {/* Messages Container */}
              <div className="chatbot-messages">
                {messages.map((msg) => (
                  <div 
                    key={msg.id} 
                    className={`message ${msg.sender}`}
                  >
                    <div className="message-avatar">
                      {msg.sender === 'bot' ? (
                        <div className="avatar-bot">
                          <Bot size={16} />
                        </div>
                      ) : (
                        <div className="avatar-user">
                          <User size={16} />
                        </div>
                      )}
                    </div>
                    <div className="message-content">
                      <div className="message-text">
                        {formatMessage(msg.text)}
                      </div>
                      <div className="message-timestamp">
                        {msg.timestamp}
                        {msg.intent && (
                          <span className="intent-tag">{msg.intent}</span>
                        )}
                      </div>
                    </div>
                  </div>
                ))}
                
                {isLoading && (
                  <div className="message bot">
                    <div className="message-avatar">
                      <div className="avatar-bot">
                        <Bot size={16} />
                      </div>
                    </div>
                    <div className="message-content">
                      <div className="typing-indicator">
                        <span></span>
                        <span></span>
                        <span></span>
                      </div>
                    </div>
                  </div>
                )}
                
                <div ref={messagesEndRef} />
              </div>

              {/* Quick Actions */}
              <div className="quick-actions">
                <div className="quick-actions-header">
                  <HelpCircle size={16} />
                  <span>Quick Actions</span>
                </div>
                <div className="quick-actions-grid">
                  {quickActions.map((action, index) => (
                    <button
                      key={index}
                      className="quick-action-btn"
                      onClick={() => handleQuickAction(action.query)}
                      title={action.query}
                    >
                      {action.icon}
                      <span>{action.label}</span>
                    </button>
                  ))}
                </div>
              </div>

              {/* Suggestions */}
              <div className="suggestions">
                <div className="suggestions-header">
                  <Search size={16} />
                  <span>Try asking:</span>
                </div>
                <div className="suggestions-list">
                  {exampleQueries.map((suggestion, index) => (
                    <button
                      key={index}
                      className="suggestion-chip"
                      onClick={() => handleSuggestionClick(suggestion)}
                    >
                      {suggestion}
                    </button>
                  ))}
                </div>
              </div>

              {/* Input Area */}
              <div className="chatbot-input">
                <div className="input-wrapper">
                  <input
                    type="text"
                    value={inputText}
                    onChange={(e) => setInputText(e.target.value)}
                    onKeyPress={handleKeyPress}
                    placeholder="Ask about fees, attendance, results, tasks, events..."
                    disabled={isLoading}
                  />
                  <button 
                    className="send-btn"
                    onClick={() => sendMessage()}
                    disabled={!inputText.trim() || isLoading}
                  >
                    {isLoading ? (
                      <Loader size={20} className="loading-spinner" />
                    ) : (
                      <Send size={20} />
                    )}
                  </button>
                </div>
                <div className="input-hint">
                  Press Enter to send • Ask multiple things at once
                </div>
              </div>
            </>
          )}
        </div>
      )}

