        }
        
        .suggestions {
          padding: 16px 20px;
          border-bottom: 1px solid #e2e8f0;
          background: white;
        }
        
        .suggestions-header {
          display: flex;
          align-items: center;
          gap: 8px;
          margin-bottom: 12px;
          font-size: 13px;
          font-weight: 600;
          color: #475569;
        }
        
        .suggestions-list {
          display: flex;
          flex-wrap: wrap;
          gap: 8px;
        }
        
        .suggestion-chip {
          padding: 6px 12px;
          background: #eef2ff;
          border: 1px solid #c7d2fe;
          border-radius: 20px;
          font-size: 12px;
          color: #4f46e5;
          cursor: pointer;
          transition: all 0.2s;
        }
        
        .suggestion-chip:hover {
          background: #c7d2fe;
          border-color: #a5b4fc;
        }
        
        .chatbot-input {
          padding: 16px 20px;
          background: white;
        }
        
        .input-wrapper {
          display: flex;
          gap: 12px;
          margin-bottom: 8px;
        }
        
        .input-wrapper input {
          flex: 1;
          padding: 12px 16px;
          border: 1px solid #e2e8f0;
          border-radius: 12px;
          font-size: 14px;
          outline: none;
          transition: border 0.2s;
        }
        
        .input-wrapper input:focus {
          border-color: #667eea;
          box-shadow: 0 0 0 3px rgba(102, 126, 234, 0.1);
        }
        
        .send-btn {
          width: 48px;
          height: 48px;
          background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
          border: none;
          border-radius: 12px;
          color: white;
          cursor: pointer;
          display: flex;
          align-items: center;
          justify-content: center;
          transition: all 0.2s;
        }
        
        .send-btn:hover:not(:disabled) {
          transform: translateY(-2px);
          box-shadow: 0 4px 12px rgba(102, 126, 234, 0.4);
        }
        
        .send-btn:disabled {
          opacity: 0.5;
          cursor: not-allowed;
        }
        
        .loading-spinner {
          animation: spin 1s linear infinite;
        }
        
        @keyframes spin {
          from { transform: rotate(0deg); }
          to { transform: rotate(360deg); }
        }
        
        .input-hint {
          font-size: 11px;
          color: #94a3b8;
          text-align: center;
        }
        
        /* Responsive */
        @media (max-width: 500px) {
          .chatbot-modal {
            width: calc(100vw - 40px);
            height: calc(100vh - 100px);
            bottom: 20px;
            right: 20px;
            left: 20px;
          }
          
          .quick-actions-grid {
            grid-template-columns: repeat(2, 1fr);
          }
        }
      `}</style>
    </>
  );
};

export default ChatbotInterface;
